// 03 · Normalize — read original webhook (Set node must not wipe body)
const webhook = $('01 · Receive Order Webhook').first().json;
const body = webhook.body ?? webhook;
const loc =
  $('02 · Set GHL Location ID').first().json.locationId ||
  'uc3GK4buCjDTCkedqWyy';

const customer = body.customer || {};
const order = body.order || {};
const phone = (
  customer.phone_e164 ||
  customer.phone ||
  customer.phone_raw ||
  ''
)
  .toString()
  .trim();
const rawName = (customer.name || '').toString().trim();
const firstName = rawName.split(/\s+/)[0] || 'Guest';
const lastName = rawName.split(/\s+/).slice(1).join(' ') || 'Caller';

const orderType = (order.order_type || '').toString().toLowerCase();
const channel = (body.channel || '').toString().toLowerCase() || null;
const status = (order.status || 'placed').toString().toLowerCase();
const lastOrderId =
  order.clover_order_id || body.session_id || body.event_id || null;
const total = order.total ?? null;

const items = Array.isArray(order.items) ? order.items : [];
const summary =
  items.length > 0
    ? items
        .map((i) => {
          const qty = i.qty ?? i.quantity ?? 1;
          const name = i.name || 'item';
          return `${qty}x ${name}`;
        })
        .join(', ')
    : null;

// Tags applied in step 07 (append). Do NOT send tags on upsert (would risk replace).
const tagsToAdd = ['voice-order', 'order-placed'];
if (orderType === 'pickup') tagsToAdd.push('pickup');
if (orderType === 'delivery') tagsToAdd.push('delivery');

// Custom field IDs — docs/plan/13-ghl-n8n-order-sync.md §7.1
const customFields = [
  { id: '0QK5vxB5ntrYG44o33Gn', field_value: lastOrderId != null ? String(lastOrderId) : '' },
  { id: 'nl3jIwfxyUgQHPRlbGZl', field_value: orderType || '' },
  { id: 'Q59Rb7F84BNHvrL1gzOJ', field_value: status || 'placed' },
  {
    id: 'IeLzeT4I8xitx3Jvk9mQ',
    field_value: total != null && total !== '' ? Number(total) : '',
  },
  { id: 'FyLZbBVUDD9TzY7LXlm4', field_value: summary || '' },
  { id: 'UUqkRGbEl5HjS5Sd2eIz', field_value: channel || '' },
].filter((f) => f.field_value !== '' && f.field_value !== null && f.field_value !== undefined);

const upsertBody = {
  locationId: loc,
  phone,
  firstName,
  lastName,
  source: 'Voice Agent',
  customFields,
};

return {
  json: {
    locationId: loc,
    event: body.event || 'unknown',
    event_id: body.event_id || null,
    session_id: body.session_id || null,
    channel,
    phone,
    firstName,
    lastName,
    fullName: rawName || null,
    order_type: orderType || null,
    clover_order_id: order.clover_order_id || null,
    order_total: total,
    order_summary: summary,
    tagsToAdd,
    upsertBody,
    hasPhone: phone.length >= 7,
    raw: body,
  },
};

const norm = $('03 · Normalize Order Payload').item.json;
const upsert = $('05 · GHL · Upsert Contact + Fields').first().json;
const tagsResp = $input.first().json;
const status = upsert.statusCode ?? upsert.status ?? null;
const ok =
  status === undefined ||
  status === null ||
  (Number(status) >= 200 && Number(status) < 300);

return {
  json: {
    ok: true,
    event: norm.event,
    event_id: norm.event_id,
    phone: norm.phone,
    tags: norm.tagsToAdd,
    order_summary: norm.order_summary,
    ghl_http_status: status,
    ghl_ok: ok,
    ghl_contact_id: upsert.contact?.id || null,
    ghl_tags_ok: !(tagsResp.statusCode >= 400),
    sms_rearm: 'removed order-placed then re-added',
  },
};
